/**
 * Convert a Date object to a local YYYY-MM-DD string.
 */
export function toLocalDateKey(date: Date): string {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
}

/**
 * Convert an ISO timestamp string (e.g. "2026-02-15T15:00:00Z") to a local YYYY-MM-DD string.
 */
export function isoToLocalDateKey(isoString: string): string {
  return toLocalDateKey(new Date(isoString))
}

/**
 * Parse a YYYY-MM-DD string as a local date (not UTC).
 * `new Date("2026-02-15")` parses as UTC midnight, which can shift the day
 * when using local getters. This function avoids that issue.
 */
export function parseDateKey(dateKey: string): Date {
  const [year, month, day] = dateKey.split('-').map(Number)
  return new Date(year, month - 1, day)
}
